import { test, expect } from '@playwright/test';

test.use({ storageState: 'studio/.auth/successfactors.json' });

test('Onboarding dashboard: Data Collection and Compliance Forms status for Matthew Moraga', async ({ page }) => {
  await test.step('Navigate to SuccessFactors home page', async () => {
    await page.goto('https://performancemanager8.successfactors.com/sf/start');
  });

  await test.step('Open the navigation menu via Home button', async () => {
    await page.getByRole('button', { name: 'Home' }).click();
    await page.waitForTimeout(1500);
  });

  await test.step('Select Onboarding from the navigation flyout', async () => {
    // The selector is "Onboarding menu item in the navigation flyout"
    // Use text selector as per exploration (since it's not a role-based selector)
    await page.getByText('Onboarding', { exact: true }).click();
    await page.waitForTimeout(1500);
  });

  await test.step('Wait for Onboarding dashboard to load', async () => {
    // Wait for either heading or search input
    await Promise.race([
      page.getByRole('heading', { name: /Onboarding/i }).waitFor({ state: 'visible', timeout: 10000 }),
      page.locator('input[placeholder="Search for new recruit"]').waitFor({ state: 'visible', timeout: 10000 }),
    ]);
  });

  await test.step('Wait for and fill the Search for new recruit input', async () => {
    const searchInput = page.locator('input[placeholder="Search for new recruit"]');
    await searchInput.waitFor({ state: 'visible', timeout: 10000 });
    await searchInput.fill('Matthew Moraga');
  });

  await test.step('Select Matthew Moraga from the typeahead dropdown', async () => {
    await page.getByRole('option', { name: /^Matthew Moraga/ }).click();
    await page.waitForTimeout(1500);
  });

  await test.step('Click the Go button to apply the filter', async () => {
    await page.getByRole('button', { name: 'Go' }).click();
    await page.waitForTimeout(1500);
  });

  await test.step('Wait for the candidate table to update and show Matthew Moraga\'s row', async () => {
    // Wait for at least one row to appear
    await page.locator('ui5-table-row').first().waitFor({ state: 'visible', timeout: 10000 });
  });

  let dataCollectionStatus = '';
  let complianceFormsStatus = '';

  await test.step('Read Data Collection and Compliance Forms statuses from Matthew Moraga\'s row', async () => {
    // Assume only one row is present after filtering
    const row = page.locator('ui5-table-row').first();
    dataCollectionStatus = (await row.locator('ui5-table-cell').nth(3).innerText()).trim();
    complianceFormsStatus = (await row.locator('ui5-table-cell').nth(4).innerText()).trim();
  });

  await test.step('Assert both statuses are Completed', async () => {
    expect(dataCollectionStatus).toBe('Completed');
    expect(complianceFormsStatus).toBe('Completed');
  });
});
